PigeonInternalCodecSerializer::PigeonInternalCodecSerializer() {}

EncodableValue PigeonInternalCodecSerializer::ReadValueOfType(
    uint8_t type, ::flutter::ByteStreamReader* stream) const {
  switch (type) {
    case 129: {
      const auto& encodable_enum_arg = ReadValue(stream);
      const int64_t enum_arg_value =
          encodable_enum_arg.IsNull() ? 0 : encodable_enum_arg.LongValue();
      return encodable_enum_arg.IsNull()
                 ? EncodableValue()
                 : CustomEncodableValue(
                       static_cast<InternalStorageTaskState>(enum_arg_value));
    }
    case 130: {
      return CustomEncodableValue(InternalStorageFirebaseApp::FromEncodableList(
          std::get<EncodableList>(ReadValue(stream))));
    }
    case 131: {
      return CustomEncodableValue(InternalStorageReference::FromEncodableList(
          std::get<EncodableList>(ReadValue(stream))));
    }
    case 132: {
      return CustomEncodableValue(InternalFullMetaData::FromEncodableList(
          std::get<EncodableList>(ReadValue(stream))));
    }
    case 133: {
      return CustomEncodableValue(InternalListOptions::FromEncodableList(
          std::get<EncodableList>(ReadValue(stream))));
    }
    case 134: {
      return CustomEncodableValue(InternalSettableMetadata::FromEncodableList(
          std::get<EncodableList>(ReadValue(stream))));
    }
    case 135: {
      return CustomEncodableValue(
          InternalStorageTaskSnapShot::FromEncodableList(
              std::get<EncodableList>(ReadValue(stream))));
    }
    case 136: {
      return CustomEncodableValue(InternalListResult::FromEncodableList(
          std::get<EncodableList>(ReadValue(stream))));
    }
    default:
      return ::flutter::StandardCodecSerializer::ReadValueOfType(type, stream);
  }
}

void PigeonInternalCodecSerializer::WriteValue(
    const EncodableValue& value, ::flutter::ByteStreamWriter* stream) const {
  if (const CustomEncodableValue* custom_value =
          std::get_if<CustomEncodableValue>(&value)) {
    if (custom_value->type() == typeid(InternalStorageTaskState)) {
      stream->WriteByte(129);
      WriteValue(EncodableValue(static_cast<int>(
                     std::any_cast<InternalStorageTaskState>(*custom_value))),
                 stream);
      return;
    }
    if (custom_value->type() == typeid(InternalStorageFirebaseApp)) {
      stream->WriteByte(130);
      WriteValue(EncodableValue(
                     std::any_cast<InternalStorageFirebaseApp>(*custom_value)
                         .ToEncodableList()),
                 stream);
      return;
    }
    if (custom_value->type() == typeid(InternalStorageReference)) {
      stream->WriteByte(131);
      WriteValue(
          EncodableValue(std::any_cast<InternalStorageReference>(*custom_value)
                             .ToEncodableList()),
          stream);
      return;
    }
    if (custom_value->type() == typeid(InternalFullMetaData)) {
      stream->WriteByte(132);
      WriteValue(
          EncodableValue(std::any_cast<InternalFullMetaData>(*custom_value)
                             .ToEncodableList()),
          stream);
      return;
    }
    if (custom_value->type() == typeid(InternalListOptions)) {
      stream->WriteByte(133);
      WriteValue(
          EncodableValue(std::any_cast<InternalListOptions>(*custom_value)
                             .ToEncodableList()),
          stream);
      return;
    }
    if (custom_value->type() == typeid(InternalSettableMetadata)) {
      stream->WriteByte(134);
      WriteValue(
          EncodableValue(std::any_cast<InternalSettableMetadata>(*custom_value)
                             .ToEncodableList()),
          stream);
      return;
    }
    if (custom_value->type() == typeid(InternalStorageTaskSnapShot)) {
      stream->WriteByte(135);
      WriteValue(EncodableValue(
                     std::any_cast<InternalStorageTaskSnapShot>(*custom_value)
                         .ToEncodableList()),
                 stream);
      return;
    }
    if (custom_value->type() == typeid(InternalListResult)) {
      stream->WriteByte(136);
      WriteValue(EncodableValue(std::any_cast<InternalListResult>(*custom_value)
                                    .ToEncodableList()),
                 stream);
      return;
    }
  }
  ::flutter::StandardCodecSerializer::WriteValue(value, stream);
}

/// The codec used by FirebaseStorageHostApi.
const ::flutter::StandardMessageCodec& FirebaseStorageHostApi::GetCodec() {
  return ::flutter::StandardMessageCodec::GetInstance(
      &PigeonInternalCodecSerializer::GetInstance());
}

